class Solution:
    def mergeAlternately(self, word1, word2):
        m = min(len(word1), len(word2))
        parts = []
        for i in range(m):
            parts.append(word1[i])
            parts.append(word2[i])
        parts.append(word1[m:])
        parts.append(word2[m:])
        return ''.join(parts)

