var mergeAlternately = function(word1, word2) {
    const m = Math.min(word1.length, word2.length);
    let res = '';
    for (let i = 0; i < m; i++) {
        res += word1[i] + word2[i];
    }
    res += word1.slice(m) + word2.slice(m);
    return res;
};
